package multidimensionais.arrays.praticando.aprendendo;public class ArraysMultidimensionaisForEach {    public static void main(String[] args) {        int[][] numerosMulti = new int[3][3];        numerosMulti[0][0] = 10;        numerosMulti[0][1] = 20;        numerosMulti[0][2] = 30;        numerosMulti[1][0] = 40;        numerosMulti[1][1] = 50;        numerosMulti[1][2] = 60;        numerosMulti[2][0] = 70;        numerosMulti[2][1] = 80;        numerosMulti[2][2] = 90;        for (int[] arrayBase : numerosMulti){            for (int j : arrayBase){                System.out.println(j);            }        }    }}